+        if (exported.length > 0) {
+          console.log(`Exported ${exported.length} file(s):`);
+          for (const f of exported) {
+            console.log(`  ✓ ${f}`);
+          }
+        }
+        if (errors.length > 0) {
+          console.error(`Failed to export ${errors.length} file(s):`);
+          for (const e of errors) {
+            console.error(`  ✗ ${e.id}: ${e.error}`);
